// ส่วนหนึ่งใน Navbar.tsx
{session ? (
  <div style={profileActionGroup}>
    {/* เปลี่ยนจาก Link เป็น div เพื่อไม่ให้กดได้ */}
    <div style={profileDisplayOnly}>
      <div style={avatarWrapper}>
        {session.user?.image ? (
          <img src={session.user.image} alt="Profile" style={avatarImage} />
        ) : (
          <div style={avatarFallback}>{session.user?.name?.[0] || "U"}</div>
        )}
      </div>
      <span style={userNameText}>
        {session.user?.name}
      </span>
    </div>

    <button className="btn" onClick={() => signOut({ callbackUrl: "/" })} style={logoutBtnStyle}>
      Logout
    </button>
  </div>
) : (
  <button className="btn" onClick={() => signIn()}>Login</button>
)}

// สไตล์เพิ่มเติมสำหรับโหมดโชว์อย่างเดียว
const profileDisplayOnly = {
  display: 'flex',
  alignItems: 'center',
  gap: '12px',
  padding: '6px 16px',
  borderRadius: '15px',
  background: '#f8fafc', // พื้นหลังเนียนๆ แบบ Enterprise
  border: '1px solid #f1f5f9',
  cursor: 'default' // เปลี่ยนเมาส์ให้เป็นรูปปกติ ไม่ใช่รูปมือ
};